class Solution:
    def FindNumbersWithSum(self, array, tsum):
        if not array or not tsum:
            return []
        front = 0
        rear = len(array) - 1
        while front < rear:
            added = array[front] + array[rear]
            if added == tsum:
                return [array[front], array[rear]]
            elif added < tsum:
                front += 1
            else:
                rear -= 1
        return []
